/**
 * @param {string[]} chunks
 * @param {string[]} queries
 * @return {number[]}
 */
function solve(chunks, queries) {
    const S = chunks.join("");
    const N = S.length;

    // Map to store counts of every unique word found in S
    const wordCounts = new Map();

    /**
     * Checks if a character is a lowercase English letter.
     * @param {string} char
     * @returns {boolean}
     */
    const isLetter = (char) => {
        return char >= 'a' && char <= 'z';
    };

    let i = 0;
    while (i < N) {
        // 1. Skip separators (non-word characters)
        while (i < N && !isLetter(S[i]) && S[i] !== '-') {
            i++;
        }
        if (i === N) break;

        // 2. Extract maximal segment P containing only letters and hyphens
        const startP = i;
        let j = i;
        while (j < N && (isLetter(S[j]) || S[j] === '-')) {
            j++;
        }
        const P = S.substring(startP, j);

        // 3. Parse P into words
        let currentWord = "";
        const P_len = P.length;

        for (let k = 0; k < P_len; k++) {
            const charP = P[k];

            if (isLetter(charP)) {
                currentWord += charP;
            } else if (charP === '-') {
                // Check if the hyphen is surrounded by letters within P
                // W must be non-empty (i.e., preceded by a letter)
                // P[k+1] must be a letter
                const precededByLetter = currentWord.length > 0 && isLetter(currentWord[currentWord.length - 1]);
                const followedByLetter = k + 1 < P_len && isLetter(P[k + 1]);

                if (precededByLetter && followedByLetter) {
                    currentWord += '-';
                } else {
                    // Hyphen acts as a separator. Finalize the current word.
                    if (currentWord.length > 0) {
                        wordCounts.set(currentWord, (wordCounts.get(currentWord) || 0) + 1);
                        currentWord = "";
                    }
                    // If currentWord was empty, this hyphen is just skipped as a separator.
                }
            }
        }

        // 4. Handle the last word in P if it exists
        if (currentWord.length > 0) {
            wordCounts.set(currentWord, (wordCounts.get(currentWord) || 0) + 1);
        }

        // Move index i past segment P
        i = j;
    }

    // 5. Generate the result array for queries
    const ans = [];
    for (const query of queries) {
        ans.push(wordCounts.get(query) || 0);
    }

    return ans;
}

