func solve(chunks []string, queries []string) []int64 {
	S := strings.Join(chunks, "")
	N := len(S)

	// Map to store counts of every unique word found in S
	wordCounts := make(map[string]int64)

	// Helper function to check if a rune is a lowercase English letter.
	isLetter := func(r rune) bool {
		return r >= 'a' && r <= 'z'
	}

	i := 0
	for i < N {
		r_i := rune(S[i])

		// 1. Skip separators (non-word characters)
		// Separators are anything that is not a letter or a hyphen.
		if !isLetter(r_i) && r_i != '-' {
			i++
			continue
		}

		// Start of a potential segment P (contains only letters and hyphens)
		startP := i
		j := i
		for j < N {
			r_j := rune(S[j])
			if isLetter(r_j) || r_j == '-' {
				j++
			} else {
				break
			}
		}
		// P is S[startP:j]
		P := S[startP:j]
		P_runes := []rune(P)
		P_len := len(P_runes)

		// 2. Parse P into words
		currentWord := ""

		for k := 0; k < P_len; k++ {
			charP := P_runes[k]

			if isLetter(charP) {
				currentWord += string(charP)
			} else if charP == '-' {
				// Check if the hyphen is surrounded by letters within P

