        while (i < N && !isLetter(S[i]) && S[i] !== '-') {
            i++;
        }
        if (i === N) break;

        // 2. Extract maximal segment P containing only letters and hyphens
        const startP = i;
        let j = i;
        while (j < N && (isLetter(S[j]) || S[j] === '-')) {
            j++;
        }
        const P = S.substring(startP, j);

        // 3. Parse P into words
        let currentWord = "";
        const P_len = P.length;

        for (let k = 0; k < P_len; k++) {
            const charP = P[k];

